import os
import json
import time
import hashlib
from functools import wraps
from pathlib import Path
from flask import Flask, request, jsonify

app = Flask(__name__)

class DiskCache:
    def __init__(self, cache_dir='cache', default_ttl=3600):
        self.cache_dir = Path(cache_dir)
        self.cache_dir.mkdir(exist_ok=True)
        self.default_ttl = default_ttl
    
    def _get_cache_key(self, key):
        hash_key = hashlib.md5(key.encode()).hexdigest()
        return self.cache_dir / f"{hash_key}.json"
    
    def _is_expired(self, cache_data):
        if 'expires_at' not in cache_data:
            return True
        return time.time() > cache_data['expires_at']
    
    def get(self, key):
        cache_file = self._get_cache_key(key)
        
        if not cache_file.exists():
            return None
        
        try:
            with open(cache_file, 'r') as f:
                cache_data = json.load(f)
            
            if self._is_expired(cache_data):
                cache_file.unlink()
                return None
            
            return cache_data['data']
        except (json.JSONDecodeError, KeyError, IOError):
            return None
    
    def set(self, key, value, ttl=None):
        cache_file = self._get_cache_key(key)
        ttl = ttl if ttl is not None else self.default_ttl
        
        cache_data = {
            'data': value,
            'created_at': time.time(),
            'expires_at': time.time() + ttl
        }
        
        try:
            with open(cache_file, 'w') as f:
                json.dump(cache_data, f)
            return True
        except (IOError, TypeError):
            return False
    
    def delete(self, key):
        cache_file = self._get_cache_key(key)
        if cache_file.exists():
            cache_file.unlink()
            return True
        return False
    
    def clear(self):
        for cache_file in self.cache_dir.glob('*.json'):
            cache_file.unlink()
    
    def cleanup_expired(self):
        count = 0
        for cache_file in self.cache_dir.glob('*.json'):
            try:
                with open(cache_file, 'r') as f:
                    cache_data = json.load(f)
                if self._is_expired(cache_data):
                    cache_file.unlink()
                    count += 1
            except (json.JSONDecodeError, KeyError, IOError):
                cache_file.unlink()
                count += 1
        return count


cache = DiskCache(cache_dir='api_cache', default_ttl=600)


def cached_response(ttl=None, key_prefix=''):
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            cache_key_parts = [key_prefix, f.__name__, request.path]
            
            if request.args:
                sorted_args = sorted(request.args.items())
                cache_key_parts.append(str(sorted_args))
            
            if request.is_json and request.get_json(silent=True):
                json_data = request.get_json()
                cache_key_parts.append(str(sorted(json_data.items())))
            
            cache_key = ':'.join(filter(None, cache_key_parts))
            
            cached_data = cache.get(cache_key)
            if cached_data is not None:
                return jsonify(cached_data)
            
            response_data = f(*args, **kwargs)
            
            if isinstance(response_data, tuple):
                data, status_code = response_data
            else:
                data = response_data
                status_code = 200
            
            if status_code == 200:
                if hasattr(data, 'get_json'):
                    cache.set(cache_key, data.get_json(), ttl=ttl)
                elif isinstance(data, dict):
                    cache.set(cache_key, data, ttl=ttl)
            
            return response_data
        
        return decorated_function
    return decorator


